var e=[{id:`L2_1`,type:`dialog`,speaker:`CARANTISIR_ZODIAC_NULL_NULL`,text:{KOREA:`어쭙잖은 각오로 망설여서야 현실은 쇠퇴할 뿐이겠지.`,JPN:`中途半端な覚悟で迷っていては、衰退する現実が待っているだけだろう。`,ENG:`Hesitating with half-baked resolve will only lead the world to ruin.`,TWN:`沒有實力的決心只會猶豫不決，最後敗給現實。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CARANTISIR_ZODIAC_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`CARANTISIR_ZODIAC_NULL_NULL`,text:{KOREA:`우리가 추구하는 정의야말로 진정된 올바름이라는 것을, 이 창칼로 증명해 보이겠다.`,JPN:`我らの追求する正義こそが真の正しさなのだと、この槍と剣で証明してみせる。`,ENG:`I'll let these blades prove that the justice we pursue is the one true path.`,TWN:`我會用這把劍來證明，我們追求的正義才是正確的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CARANTISIR_ZODIAC_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};